<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="UTF-8">
<meta name="viewport" content="width=device-width, initial-scale=1.0">
<title>Ubuntu-like Desktop Environment</title>
<style>
  * {
    box-sizing: border-box;
  }
  body, html {
    margin: 0;
    padding: 0;
    height: 100%;
    font-family: -apple-system, BlinkMacSystemFont, "Segoe UI", Roboto, Helvetica, Arial, sans-serif;
    overflow: hidden;
    background: #000;
  }
  #desktop {
    width: 100vw;
    height: 100vh;
    background: radial-gradient(circle at 50% 30%, #4b1e3d 0%, #1a0011 100%);
    position: relative;
    overflow: hidden;
  }
  #taskbar {
    position: absolute;
    top: 0;
    left: 0;
    width: 100%;
    height: 36px;
    background: rgba(30, 30, 30, 0.95);
    display: flex;
    align-items: center;
    padding: 0 12px;
    gap: 12px;
    border-bottom: 1px solid #000;
    z-index: 1000;
  }
  #taskbar button {
    background: #3a3a3a;
    color: #eee;
    border: 1px solid #555;
    border-radius: 6px;
    padding: 6px 14px;
    cursor: pointer;
    font-size: 13px;
    font-weight: 500;
    transition: background 0.2s;
  }
  #taskbar button:hover {
    background: #4a4a4a;
  }
  .window {
    position: absolute;
    width: 480px;
    height: 320px;
    background: #2b2b2b;
    border: 1px solid #444;
    border-radius: 8px;
    display: none;
    flex-direction: column;
    box-shadow: 0 10px 30px rgba(0,0,0,0.5);
    overflow: hidden;
    z-index: 10;
  }
  #files-window {
    top: 60px;
    left: 60px;
  }
  #notepad-window {
    top: 100px;
    left: 120px;
    width: 500px;
    height: 400px;
  }
  .title-bar {
    height: 32px;
    background: #333;
    color: #fff;
    display: flex;
    align-items: center;
    justify-content: space-between;
    padding: 0 10px;
    cursor: move;
    user-select: none;
    border-top-left-radius: 8px;
    border-top-right-radius: 8px;
  }
  .win-close {
    background: #E95420;
    border: none;
    color: white;
    width: 20px;
    height: 20px;
    border-radius: 50%;
    cursor: pointer;
    font-weight: bold;
    line-height: 20px;
